public String getSandwich(String str)
{
    int first = str.indexOf("bread");
    int last = str.lastIndexOf("bread");
    if (first == last)
        return "";
    return str.substring(first + 5, last);
}

public int loneSum(int a, int b, int c)
{
    if ( a == b && b == c) {
    return 0;
  }
  if ( a != b && b == c) {
    return a;
  }
  if ( a == c && c != b) {
    return b;
  }
  if ( a == b && b != c) {
    return c;
  }
  return a + b + c;
}

