public int roundSum(int a, int b, int c)
{
    a = this.round10(a);
    b = this.round10(b);
    c = this.round10(c);

    int sum = a + b + c;

    return sum;
}

public int round10(int num)
{
    int remainder = num % 10;

    if (remainder >= 5)
    {
        // round up
        num = num + (10 - remainder);
    }
    else
    {
        // round down
        num = num - remainder;
    }

    return num;
}

