public String atFirst(String str)
{
    int length = str.length();

	if (length >= 2)
    {
		return str.substring(0, 2);
    }
	else if(length == 1)
    {
		return (str.charAt(0)+"@");
    }
	else
    {
		return "@@";
    }
}

